      if (found.isDefined) {
        val start = i
        var j = i
        while (j < body.length && !body.charAt(j).isWhitespace) j += 1
        val url = body.substring(start, j)
        urlsList = url :: urlsList
        i = j
      } else {
        i += 1
      }
    }
    urlsList
  }.distinct

