readChannelMessages("general").flatMap { msgs =>
  val prefixes = List("http://", "https://")
  val urls: List[String] = msgs.flatMap { msg =>
    var listUrls: List[String] = Nil
    val body: String = msg.body
    val n: Int = body.length
    var i: Int = 0
    while (i < n) {
      var foundPrefix: Option[String] = None
      var pi: Int = 0
      while (pi < prefixes.length && foundPrefix.isEmpty) {
        val pf: String = prefixes(pi)
        if (body.regionMatches(true, i, pf, 0, pf.length)) foundPrefix = Some(pf)
        pi += 1
      }
      foundPrefix match {
        case Some(_) =>
          val start: Int = i
          var j: Int = i
          while (j < n && !body.charAt(j).isWhitespace) j += 1
          val url: String = body.substring(start, j)
          listUrls = url :: listUrls
          i = j
        case None => i += 1
      }
    }
    listUrls
  }.distinct

  if (urls.isEmpty) {
    sendChannelMessage("random", "No URLs found in 'general' channel.")
    getWebpage("nopage").map(_ => "No URLs found; notification sent to 'random'.")
  } else {
    val combinedC: Classified[String] = {
      val firstC = getWebpage(urls.head)
      urls.tail.foldLeft(firstC) { (accC, url) =>
        accC.flatMap { content =>
          getWebpage(url).map(c => content + "\n" + c)
        }
      }
    }
    combinedC.map { allContent =>
      val summary = prompt("Summarize the following webpages in three concise bullet points:\n" + allContent)
      sendChannelMessage("random", summary)
      "Summary posted to 'random'."
    }
  }
}

