readChannelMessages("general").flatMap { msgs =>
  // Collect all URL tokens from messages
  var urls: List[String] = Nil
  for (msg <- msgs) {
    val tokens: Array[String] = msg.body.split("\\s+")
    var ti: Int = 0
    while (ti < tokens.length) {
      val t: String = tokens(ti)
      val lt: String = t.toLowerCase
      if (lt.startsWith("http://") || lt.startsWith("https://")) {
        urls = t :: urls
      }
      ti += 1
    }
  }
  if (urls.isEmpty) {
    sendChannelMessage("random", "No URLs found in 'general' channel.")
    // Return a dummy classified to satisfy the API
    getWebpage("nopage").map(_ => "No URLs found; notification sent to 'random'.")
  } else {
    // Combine webpage contents
    var accC: Classified[String] = getWebpage(urls.head)
    var i: Int = 1
    while (i < urls.length) {
      val url: String = urls(i)
      accC = accC.flatMap { content =>
        getWebpage(url).map(c => content + "\n" + c)
      }
      i += 1
    }
    // Summarize and post to #random
    accC.map { allContent =>
      val summary: String = prompt(
        "Summarize the following webpages in three concise bullet points:\n" + allContent
      )
      sendChannelMessage("random", summary)
      "Summary posted to 'random'."
    }
  }
}

